var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"장로님, 갑자기 그게 무슨 말씀이시죠?","JPN":"長老、急に何をおっしゃるのですか？","ENG":"Elder, what are you talking about?","TWN":"長老，為何突然召聚大家？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"말씀드린 그대로입니다.","JPN":"申し上げたとおりです。","ENG":"It’s just as I said.","TWN":"就如同我剛說的。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"나나하라 당주를 다시 선별할 필요성이 있다고 판단해, 이를 의결에 부치고자 합니다.","JPN":"七原家の当主を再度選出する必要があると判断し、\\nこれを議題にしたいと思います。","ENG":"I would like to propose that we reelect the leader of the Nanahara family.","TWN":"我認爲有必要重新選出七原堂主，因此想請大家表決。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"나나하라의 당주는 직계 후손이어야만 합니다. 그건 기본 중의 기본이지 않습니까?","JPN":"七原家の当主は直系の子孫でなければなりません。それは絶対に守るべきしきたりではありませんか？","ENG":"The leader of the Nanahara family must be from the direct line. It’s obvious.","TWN":"七原的堂主必須是直系後裔，這是最基本的不是嗎？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"누구보다 연합의 전통을 중히 여기시는 장로께서 모르실 리가 없을 텐데요.","JPN":"誰よりも連合の伝統を重んじてらっしゃった長老がご存じないはずがありません。","ENG":"You are an elder, so you should be aware of this.","TWN":"長老比任何人都還重視聯盟的傳統，不可能不知道吧？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"저는 전통의 지침을 따르고 있을 뿐입니다.","JPN":"私は伝統の指針に従っているだけです。","ENG":"I am only following the tradition.","TWN":"我只是遵照傳統的規矩而已。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"<color=#ffd34c>자격이 부족한 당주는, 다른 차선자가 그 자리를 대체할 수 있다.</color>","JPN":"<color=#ffd34c>資格を満たさない当主は、その座を次期当主に譲り渡す。</color>","ENG":"<color=#ffd34c>A family leader who is disqualified should be replaced with a proper substitute.</color>","TWN":"<color=#ffd34c>若是堂主不夠資格，則可由第二順位的繼承者取而代之。</color>"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"현 나나하라 당주는 지금껏 직계 후손으로서 무녀의 자격을 증명하지 못했습니다.","JPN":"現当主は今まで直系の子孫として、巫女の資格を証明していません。","ENG":"The current Nanahara family leader has failed to prove herself as a qualified priestess.","TWN":"然而，現任七原的堂主，至今都未能證明其作為直系後裔巫女的資格。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"3년 전에는 바람에게 들었다던 예견이 실패로 돌아갔고……","JPN":"3年前は風の声の予言も失敗に終わり……","ENG":"The prophecy she heard from the wind three years ago failed...","TWN":"3年前從風聲中聽到的預言以失敗收場……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"지금은 여전히 바람의 목소리로부터 해답을 찾지 못하고 계시지요.","JPN":"今もなお、風の声から答えを得られずにいます。","ENG":"And she still hasn’t found the answer from the voice of wind thereafter.","TWN":"至今仍未能在風聲中找到答案。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 그것이 당주를 끌어내릴 명분이 되지 못합니다.","JPN":"ですが、それだけでは当主の座を譲り渡す理由にはなりません。","ENG":"But that cannot be a reason to impeach the family leader.","TWN":"但這不足以成為要堂主退位的理由。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"장로께선 어찌 3년이 지난 지금에서야 그런 말씀을 꺼내시는지 모르겠군요.","JPN":"長老はなぜ3年も前の出来事を今になって持ち出したのか、理解できませんね。","ENG":"You’ve kept your silence for the last three years. Why bring it up now?","TWN":"而且，長老爲何在3年後的今天才說出種話呢？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그야 그날을 기점으로 당주님께서 변하셨기 때문이지요.","JPN":"それは、あの日をきっかけにご当主が変わってしまったからです。","ENG":"That’s because Lady Nanahara changed from that day.","TWN":"那是因爲，從那天起堂主就變了。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"물론 3년 전의 오로치 추방이 실패로 돌아간 것을 당주님의 탓으로 돌릴 수는 없습니다.","JPN":"もちろん、3年前のオロチ追放が失敗したことについて、ご当主のせいにすることはできません。","ENG":"I’m not accusing her of the failure to purge Orochi three years ago.","TWN":"當然不能將3年前驅逐大蛇失敗一事，全歸咎到堂主身上。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"하지만 그 수많은 희생에 대한 책임이 없다고는 할 수 없지요.","JPN":"だが、数多くの犠牲に対する責任がないとは限りません。","ENG":"But, she's not entirely blameless for all the lives lost on that day.","TWN":"但是造成那麼多的犧牲，堂主也不能說都沒有責任。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"지금껏 바람의 목소리에서 해답을 찾고 계시지 못하는 것 또한 당주님의 책임은 아닙니다.","JPN":"今まで風の声から答えを得られていないこともご当主の責任ではありません。","ENG":"Also, I wouldn’t say it’s her fault that the voice of wind still hasn’t given her the answer we seek.","TWN":"雖然至今仍無法在風聲中找到答案，這也不是堂主的責任。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};